using System.ComponentModel;
using System.Text.Json;
using System.Text.RegularExpressions;
using ModelContextProtocol.Server;

namespace Azure.GeneratorAgent.Mcp.Tools;

/// <summary>
/// MCP tool that adds a [CodeGenSuppress] attribute to a custom partial class
/// to suppress a duplicate member generated by the code generator.
/// Scans Generated/ to find the matching member signature and constructs
/// the correct typeof(...) list.
/// </summary>
[McpServerToolType]
public static class AddCodeGenSuppressTool
{
    // Matches method/ctor declarations with parameters in Generated/ code
    // Captures: access modifier, return type (if any), member name, parameter list
    // Use string.Format to insert the escaped member name before compiling.
    private const string MemberDeclPatternTemplate =
        @"(?:public|protected|internal|private)\s+(?:(?:static|virtual|override|async|sealed|new)\s+)*(?:(?<returnType>[\w<>\[\],\.\?]+)\s+)?(?<memberName>{0})\s*\((?<params>[^)]*)\)";

    // Matches constructor declarations specifically
    private const string CtorDeclPatternTemplate =
        @"(?:public|protected|internal|private)\s+(?:(?:static)\s+)?(?<memberName>{0})\s*\((?<params>[^)]*)\)";

    [McpServerTool(Name = "add_codegen_suppress"), Description("Add a [CodeGenSuppress] attribute to a custom partial class to suppress a duplicate member from the generator. Scans Generated/ to find the member signature.")]
    public static string Execute(
        [Description("Absolute path to the custom .cs file where the attribute should be added")] string filePath,
        [Description("Name of the member to suppress (method name or class name for constructors)")] string memberName)
    {
        try
        {
            var (success, result, error) = ExecuteInProcess(filePath, memberName);
            if (!success)
            {
                return JsonSerializer.Serialize(new { success = false, error });
            }
            return JsonSerializer.Serialize(new { success = true, result });
        }
        catch (Exception ex)
        {
            return JsonSerializer.Serialize(new { success = false, error = ex.Message });
        }
    }

    /// <summary>
    /// In-process execution for the orchestrator and batch tool.
    /// </summary>
    public static (bool Success, SuppressResult? Result, string? Error) ExecuteInProcess(string filePath, string memberName)
    {
        try
        {
            var normalizedPath = Path.GetFullPath(filePath);
            if (!File.Exists(normalizedPath))
            {
                return (false, null, $"File not found: {normalizedPath}");
            }

            var content = File.ReadAllText(normalizedPath);

            // Find the class name in the custom file
            var classMatch = CSharpPatterns.ClassDeclaration.Match(content);
            if (!classMatch.Success)
            {
                return (false, null, "Could not find class declaration in file");
            }

            var className = classMatch.Groups["className"].Value;

            // Locate the Generated/ directory relative to the custom file
            var generatedPath = FindGeneratedDirectory(normalizedPath);
            if (generatedPath is null)
            {
                return (false, null, "Could not find Generated/ directory relative to the file");
            }

            // Search generated code for the matching member
            var signatures = FindGeneratedMemberSignatures(generatedPath, className, memberName);
            if (signatures.Count == 0)
            {
                // If no generated signature found, add a parameterless suppress
                var paramlessSuppressAttr = $"[CodeGenSuppress(\"{memberName}\")]";
                if (content.Contains(paramlessSuppressAttr, StringComparison.Ordinal))
                {
                    return (true, new SuppressResult(normalizedPath, paramlessSuppressAttr, true), null);
                }

                var newContent = InsertSuppressAttribute(content, classMatch, paramlessSuppressAttr);
                File.WriteAllText(normalizedPath, newContent);
                return (true, new SuppressResult(normalizedPath, paramlessSuppressAttr, false), null);
            }

            // Add [CodeGenSuppress] for each matching signature not already present
            var addedAttributes = new List<string>();
            var currentContent = content;
            foreach (var sig in signatures)
            {
                var typeofArgs = string.Join(", ", sig.ParameterTypes.Select(t => $"typeof({t})"));
                var suppressAttr = sig.ParameterTypes.Count > 0
                    ? $"[CodeGenSuppress(\"{memberName}\", {typeofArgs})]"
                    : $"[CodeGenSuppress(\"{memberName}\")]";

                if (currentContent.Contains(suppressAttr, StringComparison.Ordinal))
                {
                    continue;
                }

                // Re-find the class match in updated content
                var updatedClassMatch = CSharpPatterns.ClassDeclaration.Match(currentContent);
                if (updatedClassMatch.Success)
                {
                    currentContent = InsertSuppressAttribute(currentContent, updatedClassMatch, suppressAttr);
                    addedAttributes.Add(suppressAttr);
                }
            }

            if (addedAttributes.Count > 0)
            {
                // Write once with all attributes applied
                File.WriteAllText(normalizedPath, currentContent);

                // Then add the using directive if needed (operates on the already-written file)
                if (!currentContent.Contains("using Microsoft.TypeSpec.Generator.Customizations;", StringComparison.Ordinal))
                {
                    AddUsingDirectiveTool.ExecuteInProcess(normalizedPath, "Microsoft.TypeSpec.Generator.Customizations");
                }
            }

            var resultAttr = addedAttributes.Count > 0
                ? string.Join(Environment.NewLine, addedAttributes)
                : signatures.Count > 0 ? "All suppress attributes already present" : "No matching signatures found";

            return (true, new SuppressResult(normalizedPath, resultAttr, addedAttributes.Count == 0), null);
        }
        catch (Exception ex)
        {
            return (false, null, ex.Message);
        }
    }

    /// <summary>
    /// Finds the Generated/ directory by walking up from the file to find src/.
    /// </summary>
    internal static string? FindGeneratedDirectory(string filePath)
    {
        var dir = Path.GetDirectoryName(filePath);
        while (dir is not null)
        {
            var generatedPath = Path.Combine(dir, "Generated");
            if (Directory.Exists(generatedPath))
            {
                // Verify we're inside a src/ tree
                var dirName = Path.GetFileName(dir);
                if (string.Equals(dirName, "src", StringComparison.OrdinalIgnoreCase) ||
                    dir.Contains(Path.DirectorySeparatorChar + "src" + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase))
                {
                    return generatedPath;
                }
            }

            var parent = Path.GetDirectoryName(dir);
            if (parent == dir)
            {
                break;
            }

            dir = parent;
        }

        return null;
    }

    /// <summary>
    /// Searches Generated/ code for members matching the given class and member name.
    /// Returns the parameter type lists for constructing typeof(...) arguments.
    /// </summary>
    internal static List<MemberSignature> FindGeneratedMemberSignatures(string generatedPath, string className, string memberName)
    {
        var signatures = new List<MemberSignature>();
        if (!Directory.Exists(generatedPath))
        {
            return signatures;
        }

        // Determine if this is a constructor (member name matches class name)
        var isCtor = string.Equals(className, memberName, StringComparison.Ordinal);

        // Compile patterns once outside the loop
        var classPattern = new Regex(
            $@"(?:public|internal)\s+(?:static\s+)?(?:partial\s+)?class\s+{Regex.Escape(className)}\b",
            RegexOptions.Compiled);
        var memberPattern = isCtor
            ? new Regex(string.Format(CtorDeclPatternTemplate, Regex.Escape(memberName)), RegexOptions.Compiled)
            : new Regex(string.Format(MemberDeclPatternTemplate, Regex.Escape(memberName)), RegexOptions.Compiled);

        foreach (var file in Directory.GetFiles(generatedPath, "*.cs", SearchOption.AllDirectories))
        {
            var content = File.ReadAllText(file);

            // Check if this file contains the class we're looking for
            if (!content.Contains(className, StringComparison.Ordinal))
            {
                continue;
            }

            // Verify the class is actually declared in this file
            if (!classPattern.IsMatch(content))
            {
                continue;
            }

            // Search for matching member declarations

            foreach (Match match in memberPattern.Matches(content))
            {
                var paramsStr = match.Groups["params"].Value.Trim();
                var paramTypes = ParseParameterTypes(paramsStr);
                signatures.Add(new MemberSignature { ParameterTypes = paramTypes });
            }
        }

        return signatures;
    }

    /// <summary>
    /// Parses a C# parameter list into a list of type names suitable for typeof().
    /// E.g., "string name, int count" → ["string", "int"]
    /// Handles generic types, nullable, arrays, and default values.
    /// </summary>
    internal static List<string> ParseParameterTypes(string parameterList)
    {
        if (string.IsNullOrWhiteSpace(parameterList))
        {
            return [];
        }

        var types = new List<string>();
        var depth = 0;
        var current = new System.Text.StringBuilder();

        // Split by commas, respecting generic angle brackets
        for (var i = 0; i < parameterList.Length; i++)
        {
            var ch = parameterList[i];
            switch (ch)
            {
                case '<':
                    depth++;
                    current.Append(ch);
                    break;
                case '>':
                    depth--;
                    current.Append(ch);
                    break;
                case ',' when depth == 0:
                    types.Add(ExtractType(current.ToString()));
                    current.Clear();
                    break;
                default:
                    current.Append(ch);
                    break;
            }
        }

        if (current.Length > 0)
        {
            types.Add(ExtractType(current.ToString()));
        }

        return types;
    }

    /// <summary>
    /// Extracts the type name from a parameter declaration like "string name = null".
    /// Strips parameter modifiers (ref, out, in, params), default values, and the parameter name.
    /// </summary>
    private static string ExtractType(string paramDecl)
    {
        var trimmed = paramDecl.Trim();

        // Remove parameter modifiers
        string[] modifiers = ["ref ", "out ", "in ", "params ", "this "];
        foreach (var mod in modifiers)
        {
            if (trimmed.StartsWith(mod, StringComparison.Ordinal))
            {
                trimmed = trimmed[mod.Length..];
                break;
            }
        }

        // Remove default value
        var eqIdx = trimmed.IndexOf('=');
        if (eqIdx >= 0)
        {
            trimmed = trimmed[..eqIdx].Trim();
        }

        // The type is everything except the last token (the parameter name)
        // Handle generic types by counting angle brackets
        var lastSpace = -1;
        var bracketDepth = 0;
        for (var i = 0; i < trimmed.Length; i++)
        {
            switch (trimmed[i])
            {
                case '<':
                    bracketDepth++;
                    break;
                case '>':
                    bracketDepth--;
                    break;
                case ' ' when bracketDepth == 0:
                    lastSpace = i;
                    break;
            }
        }

        return lastSpace >= 0 ? trimmed[..lastSpace].Trim() : trimmed;
    }

    /// <summary>
    /// Inserts a [CodeGenSuppress(...)] attribute on the line before the class declaration.
    /// </summary>
    private static string InsertSuppressAttribute(string content, Match classMatch, string attribute)
    {
        // Find the beginning of the line containing the class declaration
        // Walk back to find the start of the attribute/class block (skip existing attributes)
        var classLineStart = content.LastIndexOf('\n', classMatch.Index) + 1;

        // Detect indentation
        var indentLength = 0;
        while (classLineStart + indentLength < content.Length && content[classLineStart + indentLength] is ' ' or '\t')
        {
            indentLength++;
        }
        var indent = content.Substring(classLineStart, indentLength);

        var insertion = $"{indent}{attribute}\n";
        return content.Insert(classLineStart, insertion);
    }
}
